#!/usr/bin/env python3
"""
Douyin video downloader using yt-dlp with F2 library support.
Outputs JSON for IPC communication with Electron.
"""

import sys
import json
import os
from pathlib import Path

try:
    import yt_dlp
except ImportError:
    print(json.dumps({
        "success": False,
        "error": "yt-dlp Python module not installed. Run: pip install yt-dlp"
    }))
    sys.exit(1)


class DouyinDownloader:
    """Handle Douyin video downloads with progress tracking"""

    def __init__(self, url, output_dir=None):
        self.url = url
        self.output_dir = output_dir or str(Path.home() / "Desktop")
        self.info = None
        self.progress = 0

    def extract_info(self):
        """Extract video information without downloading"""
        try:
            ydl_opts = {
                'quiet': True,
                'no_warnings': True,
                'dump_single_json': True,
                'extract_flat': False,
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                self.info = ydl.extract_info(self.url, download=False)

            if not self.info:
                return {"success": False, "error": "Failed to extract video info"}

            # Format the response
            response = {
                "success": True,
                "info": self._format_info()
            }
            return response

        except Exception as e:
            return {
                "success": False,
                "error": f"Extraction failed: {str(e)}"
            }

    def download(self, mode='video'):
        """
        Download the video with progress tracking.
        Mode: 'video', 'audio', or 'both'
        """
        try:
            # Determine format based on mode
            if mode == 'audio':
                format_selector = 'bestaudio/best'
                postprocessors = [{
                    'key': 'FFmpegExtractAudio',
                    'preferredcodec': 'mp3',
                    'preferredquality': '192',
                }]
                ext = 'mp3'
            elif mode == 'video':
                format_selector = 'bestvideo[ext=mp4]+bestaudio[ext=m4a]/best[ext=mp4]/best'
                postprocessors = []
                ext = 'mp4'
            else:  # both
                format_selector = 'bestvideo+bestaudio/best'
                postprocessors = [{'key': 'FFmpegVideoConverter', 'preferedformat': 'mp4'}]
                ext = 'mp4'

            # Progress callback
            def progress_hook(d):
                if d['status'] == 'downloading':
                    try:
                        self.progress = d.get('downloaded_bytes', 0) / d.get('total_bytes', 1) * 100
                        # Send progress to stdout as JSON
                        print(json.dumps({
                            "type": "progress",
                            "percent": round(self.progress, 2),
                            "speed": d.get('speed', 0),
                            "eta": d.get('eta', 0)
                        }), flush=True)
                    except (ZeroDivisionError, KeyError):
                        pass
                elif d['status'] == 'finished':
                    print(json.dumps({
                        "type": "progress",
                        "percent": 100,
                        "status": "converting"
                    }), flush=True)

            ydl_opts = {
                'format': format_selector,
                'outtmpl': os.path.join(self.output_dir, '%(title)s.%(ext)s'),
                'progress_hooks': [progress_hook],
                'quiet': True,
                'no_warnings': True,
                'postprocessors': postprocessors if mode != 'video' else [],
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                ydl.download([self.url])

            return {
                "success": True,
                "message": "Download completed successfully"
            }

        except Exception as e:
            return {
                "success": False,
                "error": f"Download failed: {str(e)}"
            }

    def _format_info(self):
        """Format extracted info for display"""
        if not self.info:
            return {}

        info_dict = {
            "title": self.info.get('title', 'N/A'),
            "description": self.info.get('description', '')[:200],
            "uploader": self.info.get('uploader') or self.info.get('channel', 'N/A'),
            "duration": self.info.get('duration'),
            "view_count": self.info.get('view_count'),
            "like_count": self.info.get('like_count'),
            "upload_date": self.info.get('upload_date', '')[:10] if self.info.get('upload_date') else 'N/A',
            "webpage_url": self.info.get('webpage_url', self.url),
            "thumbnail": self.info.get('thumbnail', ''),
            "platform": 'Douyin'
        }

        return info_dict


def main():
    """CLI entry point"""
    if len(sys.argv) < 2:
        print(json.dumps({
            "success": False,
            "error": "Usage: python douyin_downloader.py <url> [mode] [output_dir]"
        }))
        sys.exit(1)

    url = sys.argv[1]
    mode = sys.argv[2] if len(sys.argv) > 2 else 'info'
    output_dir = sys.argv[3] if len(sys.argv) > 3 else None

    downloader = DouyinDownloader(url, output_dir)

    if mode == 'info':
        result = downloader.extract_info()
    elif mode in ['video', 'audio', 'both']:
        result = downloader.download(mode)
    else:
        result = {"success": False, "error": f"Unknown mode: {mode}"}

    print(json.dumps(result))
    sys.exit(0 if result.get('success') else 1)


if __name__ == '__main__':
    main()

