   373→async function extractYtdlpInfo(url, platform) {
   374→    return new Promise((resolve) => {
   375→        const args = [...baseArgs(platform), '--dump-json', '--no-playlist', url];
   376→        const proc = spawn(getYtdlp(), args);
   377→
   378→        let stdout = '';
   379→        let stderr = '';
   380→
   381→        proc.stdout.on('data', (data) => { stdout += data.toString(); });
   382→        proc.stderr.on('data', (data) => { stderr += data.toString(); });
   383→
   384→        proc.on('close', (code) => {
   385→            if (code === 0) {
   386→                try {
   387→                    const info = JSON.parse(stdout);
   388→                    const infoText = `📹 标题：${info.title || 'N/A'}
   389→
   390→👤 频道：${info.channel || info.uploader || 'N/A'}
   391→⏱️ 时长：${formatDuration(info.duration)}
   392→👁️ 观看：${formatViews(info.view_count)}
   393→
   394→📅 上传：${info.upload_date ? info.upload_date.substring(0, 10) : 'N/A'}
   395→🔗 链接：${info.webpage_url || url}
   396→
   397→📝 描述：
   398→${info.description ? info.description.substring(0, 200) + (info.description.length > 200 ? '...' : '') : '无描述'}`;
   399→                    resolve({ success: true, info: infoText });
   400→                } catch (e) {
   401→                    resolve({ success: false, error: '解析失败' });
   402→                }
   403→            } else {
   404→                resolve({ success: false, error: stderr || '获取信息失败' });
   405→            }
   406→        });
   407→
   408→        proc.on('error', () => {
   409→            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
   410→        });
   411→    });
