   169→                val name = File(videoPath).nameWithoutExtension
   170→                if (f.name.startsWith(name) && (f.extension == "vtt" || f.name.endsWith(".wordts.json"))) {
   171→                    f.delete()
   172→                }
   173→            }
   174→
   175→            _uiState.update { it.copy(
   176→                subtitles = emptyList(),
   177→                wordTimings = emptyList(),
   178→                currentCueIndex = -1,
   179→                isTranscribing = true,
   180→                statusText = "正在准备转录..."
   181→            )}
   182→
   183→            val config = aiConfigStore.config.first()
   184→
   185→            // Check Groq API Key
   186→            val hasGroqKey = config.groqApiKey.isNotBlank() ||
   187→                             (config.provider == "groq" && config.apiKey.isNotBlank())
   188→
   189→            if (!hasGroqKey) {
   190→                _uiState.update { it.copy(isTranscribing = false, statusText = "请先在 AI 设置中配置 Groq Whisper API Key") }
   191→                return@launch
   192→            }
   193→
   194→            val videoFile = File(videoPath)
   195→
   196→            // 使用分段转录服务
   197→            val result = segmentedTranscribeService.transcribeVideo(
   198→                videoFile,
   199→                config
   200→            ) { current, total, message ->
   201→                _uiState.update { it.copy(statusText = message) }
   202→            }
   203→
   204→            if (result.success && result.text.isNotBlank()) {
   205→                // Build VTT from word timestamps
   206→                val vttPath = base + ".vtt"
   207→                val wtsPath = base + ".wordts.json"
   208→                val vttBuilder = StringBuilder("WEBVTT\n\n")
   209→                val allWordTimings = mutableListOf<WordTimestamp>()
   210→
   211→                if (result.words.isNotEmpty()) {
   212→                    var curWords = mutableListOf<WordTimestamp>()
   213→                    for (wt in result.words) {
   214→                        curWords.add(wt)
   215→                        if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
