   219→                            vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
   220→                            allWordTimings.addAll(curWords)
   221→                            curWords = mutableListOf()
   222→                        }
   223→                    }
   224→                    if (curWords.isNotEmpty()) {
   225→                        val sentText = curWords.joinToString(" ") { it.w }
   226→                        val sStart = curWords.first().s
   227→                        val sEnd = curWords.last().e
   228→                        vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
   229→                        allWordTimings.addAll(curWords)
   230→                    }
   231→                }
   232→
   233→                // Save files
   234→                File(vttPath).writeText(vttBuilder.toString())
   235→                if (allWordTimings.isNotEmpty()) {
   236→                    File(wtsPath).writeText(json.encodeToString(kotlinx.serialization.builtins.ListSerializer(WordTimestamp.serializer()), allWordTimings))
   237→                }
   238→
   239→                // Reload
   240→                val subs = VttParser.parse(vttBuilder.toString())
   241→                _uiState.update { it.copy(
   242→                    subtitles = subs,
