   252→
   253→    fun setMode(mode: String) {
   254→        _uiState.update { it.copy(mode = mode, dictationIndex = _uiState.value.currentCueIndex.coerceAtLeast(0)) }
   255→    }
   256→
   257→    fun setLang(lang: String) {
   258→        _uiState.update { it.copy(currentLang = lang) }
   259→        val locale = LANGUAGES.find { it.code == lang }?.ttsLocale ?: "en-US"
   260→        tts?.language = Locale.forLanguageTag(locale)
   261→    }
   262→
   263→    /** Look up a word - ported from renderer.js showWordInline() */
   264→    fun lookupWord(word: String) {
   265→        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
   266→        speak(word)
   267→
   268→        viewModelScope.launch(Dispatchers.IO) {
   269→            val lang = _uiState.value.currentLang
   270→            val context = _uiState.value.currentSentence
   271→
   272→            // Parallel lookups
   273→            val aiConfig = aiConfigStore.config.first()
   274→            val aiTransPromise = launch { aiTranslateWord(word, context, lang, aiConfig) }
   275→
   276→            val cardData = when (lang) {
   277→                "en" -> {
   278→                    val online = dictionaryService.lookupEnglish(word)
   279→                    val translation = dictionaryService.translate(word, "en")
   280→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   281→                    WordCardData(
   282→                        word = word,
   283→                        phonetic = online?.phonetic ?: "",
   284→                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
   285→                        definitions = online?.definitions ?: emptyList(),
   286→                        examples = online?.examples ?: emptyList()
   287→                    )
   288→                }
   289→                "ja" -> {
   290→                    val online = dictionaryService.lookupJapanese(word)
   291→                    val translation = dictionaryService.translate(word, "ja")
   292→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   293→                    WordCardData(
   294→                        word = word,
   295→                        phonetic = online?.phonetic ?: "",
   296→                        translation = aiTrans ?: translation ?: "未找到释义",
   297→                        definitions = online?.definitions ?: emptyList()
   298→                    )
   299→                }
   300→                else -> {
   301→                    val translation = dictionaryService.translate(word, lang)
   302→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   303→                    WordCardData(
   304→                        word = word,
   305→                        translation = aiTrans ?: translation ?: "未找到释义"
   306→                    )
   307→                }
   308→            }
   309→            _uiState.update { it.copy(wordCardData = cardData) }
   310→        }
   311→    }
   312→
   313→    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
   314→        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
   315→        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
   316→        return aiService.chat(config, prompt)
   317→    }
   318→
   319→    fun hideWordCard() { _uiState.update { it.copy(showWordCard = false) } }
   320→
   321→    /** AI analyze sentence - ported from main.js ai-analyze-sentence */
   322→    fun analyzeSentence() {
   323→        val sentence = _uiState.value.currentSentence
   324→        if (sentence.isBlank()) return
   325→        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }
   326→
   327→        viewModelScope.launch(Dispatchers.IO) {
   328→            val lang = _uiState.value.currentLang
   329→            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
   330→            val config = aiConfigStore.config.first()
   331→            val prompt = """分析${langName}句子："$sentence"
   332→【翻译】中文翻译
   333→【语法】1-2个关键语法点
   334→【重点词汇】2-3个重要词汇及释义"""
   335→            val result = aiService.chat(config, prompt)
   336→            _uiState.update { it.copy(
   337→                isAnalyzing = false,
   338→                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
   339→            )}
   340→        }
   341→    }
   342→
   343→    /** Favorite operations */
   344→    suspend fun isFavorite(word: String): Boolean {
   345→        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
   346→    }
   347→
   348→    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
   349→        viewModelScope.launch {
   350→            val lang = _uiState.value.currentLang
   351→            if (favoriteRepository.isFavorite(word, lang)) {
   352→                favoriteRepository.remove(word, lang)
   353→            } else {
   354→                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
   355→            }
   356→        }
   357→    }
   358→
   359→    /** TTS */
   360→    fun speak(text: String) {
   361→        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
   362→    }
